#!/usr/bin/env node
/**
 * sync-legal-content (PROMPT 0 §1).
 *
 * Markdown in `legal/*.md` is the single source of truth for the legal/FAQ web
 * screens. This generator reads it and emits a typed TS module the web screens
 * import (`PrivacyPolicyWebScreen`, `FaqWebScreen`, terms). Never hand-edit the
 * generated file — edit the markdown and re-run:
 *
 *   node scripts/sync-legal-content.mjs            (write)
 *   node scripts/sync-legal-content.mjs --check    (CI: fail if stale)
 *
 * Idempotent: re-running with unchanged markdown produces byte-identical output.
 */
import fs from "node:fs";
import path from "node:path";

const ROOT = process.cwd();
const LEGAL_DIR = path.join(ROOT, "legal");
const OUT = path.join(ROOT, "packages/app/lib/legal/content.generated.ts");
const CHECK = process.argv.includes("--check");

/** Source markdown → exported constant name. */
const DOCS = [
  { file: "privacy-policy.md", constName: "PRIVACY_POLICY_MD", title: "Privacy Policy" },
  { file: "faq.md", constName: "FAQ_MD", title: "FAQ" },
  { file: "terms-of-service.md", constName: "TERMS_OF_SERVICE_MD", title: "Terms of Service" },
];

if (!fs.existsSync(LEGAL_DIR)) {
  console.error(`[sync-legal] missing ${path.relative(ROOT, LEGAL_DIR)} — legal/*.md must live at the repo root (PROMPT 0).`);
  process.exit(1);
}

const missing = DOCS.filter((d) => !fs.existsSync(path.join(LEGAL_DIR, d.file)));
if (missing.length) {
  console.error(`[sync-legal] missing markdown: ${missing.map((d) => d.file).join(", ")}`);
  process.exit(1);
}

const banner =
  "// @generated by scripts/sync-legal-content.mjs — DO NOT EDIT.\n" +
  "// Source of truth: legal/*.md. Re-run the script after editing the markdown.\n\n";

const body = DOCS.map((d) => {
  const md = fs.readFileSync(path.join(LEGAL_DIR, d.file), "utf8");
  // JSON.stringify gives a safely-escaped JS string literal (quotes, newlines, etc.).
  return `/** ${d.title} — from legal/${d.file} */\nexport const ${d.constName}: string = ${JSON.stringify(md)};`;
}).join("\n\n");

const meta =
  "\n\nexport const LEGAL_DOCS = [\n" +
  DOCS.map((d) => `  { slug: ${JSON.stringify(d.file.replace(/\\.md$/, ""))}, title: ${JSON.stringify(d.title)}, content: ${d.constName} },`).join("\n") +
  "\n] as const;\n";

const next = banner + body + meta;

if (CHECK) {
  const current = fs.existsSync(OUT) ? fs.readFileSync(OUT, "utf8") : "";
  if (current !== next) {
    console.error("[sync-legal] OUT is stale — run `node scripts/sync-legal-content.mjs` and commit.");
    process.exit(1);
  }
  console.log("[sync-legal] up to date ✓");
  process.exit(0);
}

fs.mkdirSync(path.dirname(OUT), { recursive: true });
fs.writeFileSync(OUT, next);
console.log(`[sync-legal] wrote ${path.relative(ROOT, OUT)} from ${DOCS.length} markdown files ✓`);
